class Solution {
public:
    int minSwaps(string s) {
        int n = s.size();
        int open = n / 2, close = n / 2;
        int res = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '[') {
                if (open > 0) open--;
                else res++;
            } else {
                if (close > 0) close--;
                else res++;
            }
        }
        return res;
    }
};
```

